CREATE OR REPLACE FUNCTION fpa_kep_get_seq_money_return (ai_year integer,ai_month integer,as_memno char,as_rec_sn char) RETURNS varchar AS $body$
DECLARE

  ldc_mrpay bigint;

BEGIN
  select  mrpay_amount into STRICT ldc_mrpay
  from    sc_kep_t_monthly_receive_det
  where (membership_no = as_memno)
  and (receive_month = ai_month)
  and (receive_year = ai_year)
  and (receive_seq = as_rec_sn);

  return ldc_mrpay;
END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
